import{_ as t,o,c as a,a5 as r}from"./chunks/framework.CJsA7bxt.js";const u=JSON.parse('{"title":"Keycloak","description":"","frontmatter":{},"headers":[],"relativePath":"reference/components/keycloak.md","filePath":"reference/components/keycloak.md"}'),i={name:"reference/components/keycloak.md"};function n(c,e,d,l,s,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="keycloak" tabindex="-1">Keycloak <a class="header-anchor" href="#keycloak" aria-label="Permalink to &quot;Keycloak&quot;">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p><a href="https://www.keycloak.org/" target="_blank" rel="noreferrer">Keycloak</a> serves as the internal Identity Provider (IDP) for Platform Mesh, implementing OpenID Connect, OAuth 2.0, and SAML 2.0 standards to provide centralized authentication and identity federation.</p><h2 id="runtime-role" tabindex="-1">Runtime role <a class="header-anchor" href="#runtime-role" aria-label="Permalink to &quot;Runtime role&quot;">​</a></h2><p>Keycloak integrates with Platform Mesh through two primary paths:</p><p><strong>kcp workspace authentication</strong> — Keycloak is configured as an OIDC provider through kcp&#39;s <code>WorkspaceAuthenticationConfiguration</code> resources. The Security operator creates one <code>WorkspaceAuthenticationConfiguration</code> per organization, named after the workspace, which configures a JWT authenticator pointing to the Keycloak realm issuer URL (<code>https://&lt;base-domain&gt;/keycloak/realms/&lt;workspace-name&gt;</code>). This configuration includes:</p><ul><li><strong>Audience validation</strong>: All OIDC client IDs from the organization&#39;s <code>AccountInfo</code> resource, ensuring tokens issued for any client in the realm are accepted</li><li><strong>Claim mappings</strong>: Extracts user identity from the <code>email</code> claim and groups from the <code>groups</code> claim in JWT tokens</li><li><strong>WorkspaceType linking</strong>: The configuration is referenced by all <code>WorkspaceType</code> resources labeled with the organization, applying authentication rules to all workspaces of that type</li></ul><p>This per-organization JWT configuration enables isolated identity management while maintaining consistent OIDC flows across the mesh.</p><p><strong>Portal authentication</strong> — The portal uses Keycloak&#39;s interactive browser-based OIDC flows for user authentication, establishing browser sessions that carry identity claims to downstream services.</p><p><strong>Automated provisioning</strong> — The <a href="./security-operator.html">Security operator</a> automatically configures Keycloak through <code>IdentityProviderConfiguration</code> resources. When an organization is created, the operator provisions a dedicated Keycloak realm with two pre-configured OIDC clients: a confidential client for web applications (including the portal) and a public client for CLI tools like <code>kubectl</code> with PKCE support.</p><h2 id="realm-lifecycle" tabindex="-1">Realm lifecycle <a class="header-anchor" href="#realm-lifecycle" aria-label="Permalink to &quot;Realm lifecycle&quot;">​</a></h2><p>Keycloak realms are created, updated, and deleted automatically in sync with organization lifecycle through <code>IdentityProviderConfiguration</code> resources managed by the Security operator.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>See <a href="/main/reference/components/security-operator.html#identityproviderconfiguration-idp">IdentityProviderConfiguration</a> on the Security operator page.</p></div><p><strong>Creation</strong> — When an organization is created, the Security operator provisions an <code>IdentityProviderConfiguration</code> resource named after the workspace. The IDP controller reconciles this resource and creates a corresponding Keycloak realm with the same name through the Keycloak Admin API.</p><p><strong>Configuration</strong> — Each realm is initialized with standard defaults:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Configuration</th></tr></thead><tbody><tr><td>Access token lifespan</td><td>Configurable via <code>--idp-access-token-lifespan</code> (default: 28800 seconds / 8 hours)</td></tr><tr><td>SSO session idle timeout</td><td>Matches the access token lifespan</td></tr><tr><td>Email-based authentication</td><td>Login with email enabled, email used as username</td></tr><tr><td>Self-registration</td><td>Controlled via <code>--idp-registration-allowed</code> flag (default: false)</td></tr><tr><td>SMTP integration</td><td>Optional SMTP configuration for email delivery (invites, password resets, email verification)</td></tr></tbody></table><p><strong>Updates</strong> — Realm configuration updates are applied through <code>IdentityProviderConfiguration</code> spec changes during the reconciliation.</p><p><strong>Deletion</strong> — When an <code>IdentityProviderConfiguration</code> is deleted (typically during organization deletion), the finalizer <code>core.platform-mesh.io/idp-finalizer</code> ensures:</p><ol><li>All OIDC clients in the realm are deleted</li><li>Client secrets stored in Kubernetes are removed</li><li>The Keycloak realm itself is deleted via the Admin API</li></ol><p>This lifecycle ensures that identity infrastructure is automatically provisioned and cleaned up alongside the organizational structure.</p><h2 id="client-management" tabindex="-1">Client management <a class="header-anchor" href="#client-management" aria-label="Permalink to &quot;Client management&quot;">​</a></h2><p>Each Keycloak realm provisions two OIDC clients by default, both managed through the OIDC Dynamic Client Registration protocol.</p><p><strong>Confidential workspace client</strong> — Used by web applications (including the portal):</p><table tabindex="0"><thead><tr><th>Property</th><th>Value</th></tr></thead><tbody><tr><td>Client type</td><td><code>confidential</code> — requires client secret for token exchange</td></tr><tr><td>Client name</td><td>Matches the organization workspace name</td></tr><tr><td>Redirect URIs</td><td><code>https://&lt;workspace-name&gt;.&lt;base-domain&gt;/*</code> plus any additional URIs from <code>--idp-additional-redirect-urls</code></td></tr><tr><td>Post-logout redirect URIs</td><td><code>https://&lt;workspace-name&gt;.&lt;base-domain&gt;/logout*</code></td></tr><tr><td>Grant types</td><td><code>authorization_code</code>, <code>refresh_token</code></td></tr><tr><td>Token endpoint auth method</td><td><code>client_secret_basic</code></td></tr><tr><td>Secret storage</td><td>Kubernetes secret named <code>portal-client-secret-&lt;workspace&gt;-&lt;workspace&gt;</code> in the <code>default</code> namespace</td></tr></tbody></table><p><strong>Public kubectl client</strong> — Used by CLI tools:</p><table tabindex="0"><thead><tr><th>Property</th><th>Value</th></tr></thead><tbody><tr><td>Client type</td><td><code>public</code> — no client secret required</td></tr><tr><td>Client name</td><td><code>kubectl</code></td></tr><tr><td>Redirect URIs</td><td><code>http://localhost:8000</code>, <code>http://localhost:18000</code> (configurable via <code>--idp-kubectl-client-redirect-urls</code>)</td></tr><tr><td>Grant types</td><td><code>authorization_code</code>, <code>refresh_token</code></td></tr><tr><td>Token endpoint auth method</td><td><code>none</code> (PKCE provides security for public clients)</td></tr><tr><td>Secret storage</td><td>Kubernetes secret named <code>portal-client-secret-&lt;workspace&gt;-kubectl</code> (contains registration metadata, not a client secret)</td></tr></tbody></table><p><strong>Client lifecycle</strong> — Clients are registered using OIDC Dynamic Client Registration and tracked in the <code>IdentityProviderConfiguration</code> status:</p><ul><li><strong>Registration</strong>: Clients are created via the Keycloak registration endpoint on first reconciliation</li><li><strong>Updates</strong>: Client configuration (redirect URIs, post-logout URIs) is updated when the spec changes</li><li><strong>Deletion</strong>: Clients removed from the spec are automatically deleted, including their Kubernetes secrets</li><li><strong>Status tracking</strong>: <code>ManagedClients</code> map stores <code>clientID</code> and <code>registrationClientURI</code> for each provisioned client</li></ul><p>Client credentials and registration access tokens are stored in Kubernetes secrets referenced by the <code>IdentityProviderConfiguration</code> resource, enabling the controller to manage client lifecycle through the OIDC protocol.</p><h2 id="repository" tabindex="-1">Repository <a class="header-anchor" href="#repository" aria-label="Permalink to &quot;Repository&quot;">​</a></h2><ul><li><a href="https://github.com/platform-mesh/keycloak" target="_blank" rel="noreferrer">platform-mesh/keycloak</a></li><li>Upstream: <a href="https://github.com/keycloak/keycloak" target="_blank" rel="noreferrer">keycloak/keycloak</a></li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/main/how-to-guides/access-keycloak.html">Access Keycloak</a></li><li><a href="/main/concepts/security/authentication.html">Authentication</a> — authentication concepts and Keycloak&#39;s role as internal IDP</li><li><a href="/main/concepts/identity-and-authorization.html">Identity and authorization</a> — runtime view of the authentication and authorization chain</li><li><a href="./security-operator.html">Security operator</a> — automated provisioning of Keycloak realms and clients</li></ul>',33)])])}const g=t(i,[["render",n]]);export{u as __pageData,g as default};
